	minExpectedCoalition = 20
)

// coalition scrapes Coalition App member institutions from Scoir and the
// Coalition website.
type coalition struct{}

// NewCoalition returns an Extractor for Coalition App member institutions.
func NewCoalition() Extractor { return &coalition{} }

func (c *coalition) Key() string   { return KeyCoalition }
func (c *coalition) Label() string { return "Coalition App" }

// Extract tries Scoir first, then the Coalition members page.
func (c *coalition) Extract(ctx context.Context, browser Browser) ([]string, error) {
	names, scoirErr := c.tryScoir(ctx, browser)
	if scoirErr == nil && len(names) >= minExpectedCoalition {
		return cleanNames(names), nil
	}

	names, coalErr := c.tryCoalitionDOM(ctx, browser)
	if coalErr == nil && len(names) >= minExpectedCoalition {
		return cleanNames(names), nil
	}

	// Build a combined error from all failures.
	parts := make([]string, 0, 2)
	if scoirErr != nil {
		parts = append(parts, fmt.Sprintf("scoir: %v", scoirErr))
	} else {
		parts = append(parts, fmt.Sprintf("scoir: got %d names (need %d)", len(names), minExpectedCoalition))
	}
	if coalErr != nil {
		parts = append(parts, fmt.Sprintf("coalition-dom: %v", coalErr))
	} else {
		parts = append(parts, fmt.Sprintf("coalition-dom: got %d names (need %d)", len(names), minExpectedCoalition))
	}
	return nil, fmt.Errorf("platform: coalition: all sources failed: %s", strings.Join(parts, "; "))
}

// tryScoir fetches the Scoir apply-colleges page and extracts college names.
func (c *coalition) tryScoir(ctx context.Context, browser Browser) ([]string, error) {
	js := `(async () => {
		const resp = await fetch("` + scoirURL + `");
		if (!resp.ok) throw new Error("HTTP " + resp.status);
		const html = await resp.text();
		const doc = new DOMParser().parseFromString(html, "text/html");
		const names = [];
		doc.querySelectorAll("h3, h4, [class*='college'] a, [class*='school'] a, [class*='name']").forEach(el => {
			const t = el.textContent.trim();
			if (t && t.length > 2 && t.length < 200) names.push(t);
		});
		if (names.length === 0) {
			const all = doc.querySelectorAll("a[href*='/college/'], a[href*='/school/']");
			all.forEach(el => {
				const t = el.textContent.trim();
				if (t && t.length > 2 && t.length < 200) names.push(t);
			});
		}
		return names;
	})()`
	names, err := browser.EvalStrings(ctx, js)
	if err != nil {
		return nil, fmt.Errorf("platform: coalition: scoir: %w", err)
	}
	return names, nil
}

// tryCoalitionDOM fetches the Coalition members page and extracts names.
func (c *coalition) tryCoalitionDOM(ctx context.Context, browser Browser) ([]string, error) {
	js := `(async () => {
		const resp = await fetch("` + coalitionMembersURL + `");
		if (!resp.ok) throw new Error("HTTP " + resp.status);
		const html = await resp.text();
		const doc = new DOMParser().parseFromString(html, "text/html");
		const names = [];
		doc.querySelectorAll(".summary-title a, .summary-item-list-title a, h3 a, li a").forEach(el => {
			const t = el.textContent.trim();
			if (t && t.length > 2 && t.length < 200) names.push(t);
		});
		if (names.length === 0) {
			doc.querySelectorAll("p, li, td").forEach(el => {
				const t = el.textContent.trim();
				if (t && t.length > 3 && t.length < 100 && /university|college|institute/i.test(t)) {
					names.push(t);
				}
			});
		}
		return names;
	})()`
	names, err := browser.EvalStrings(ctx, js)
	if err != nil {
		return nil, fmt.Errorf("platform: coalition: coalition-dom: %w", err)
	}
	return names, nil
}

// cleanNames deduplicates, trims, and removes empty strings.
func cleanNames(raw []string) []string {
	seen := make(map[string]bool, len(raw))
	out := make([]string, 0, len(raw))
	for _, n := range raw {
		n = strings.TrimSpace(n)
		if n == "" || seen[n] {
			continue
		}
		seen[n] = true
		out = append(out, n)
	}
	return out
}

